const callback = $json.callback_query;

if (!callback) {
  throw new Error('TELEGRAM_CALLBACK_MISSING');
}

const callbackData = String(
  callback.data ?? ''
).trim();

const separatorIndex =
  callbackData.indexOf('|');

if (separatorIndex === -1) {
  throw new Error(
    `INVALID_CALLBACK_FORMAT: ${callbackData}`
  );
}

const action = callbackData
  .slice(0, separatorIndex)
  .trim()
  .toLowerCase();

const processingId = callbackData
  .slice(separatorIndex + 1)
  .trim();

const allowedActions = [
  'review',
  'reject',
  'approve',
  'approval_reject'
];

if (!allowedActions.includes(action)) {
  throw new Error(
    `UNSUPPORTED_CALLBACK_ACTION: ${action}`
  );
}

if (!processingId.startsWith('DOC-')) {
  throw new Error(
    `INVALID_PROCESSING_ID: ${processingId}`
  );
}

const callbackQueryId =
  callback.id ?? null;

const actorUserId =
  callback.from?.id ?? null;

const actorUsername =
  callback.from?.username ?? '';

const actorFirstName =
  callback.from?.first_name ?? '';

const telegramChatId =
  callback.message?.chat?.id ?? null;

const telegramMessageId =
  callback.message?.message_id ?? null;

if (!callbackQueryId) {
  throw new Error(
    'CALLBACK_QUERY_ID_MISSING'
  );
}

if (!actorUserId) {
  throw new Error(
    'CALLBACK_ACTOR_ID_MISSING'
  );
}

if (!telegramChatId || !telegramMessageId) {
  throw new Error(
    'CALLBACK_MESSAGE_CONTEXT_MISSING'
  );
}

return {
  json: {
    callback_query_id:
      String(callbackQueryId),

    callback_data:
      callbackData,

    callback_action:
      action,

    processing_id:
      processingId,

    actor_user_id:
      String(actorUserId),

    actor_username:
      actorUsername,

    actor_first_name:
      actorFirstName,

    telegram_chat_id:
      String(telegramChatId),

    telegram_message_id:
      telegramMessageId,

    callback_received_at:
      new Date().toISOString()
  }
};

const callbackItem =
  $('invoice__callback--parse-action').first();

if (!callbackItem) {
  throw new Error(
    'PARSED_CALLBACK_NOT_FOUND'
  );
}

const callback = callbackItem.json;

const records = $input.all()
  .map(item => item.json)
  .filter(record => {
    return Boolean(
      record &&
      record.processing_id
    );
  });

let authorized = true;
let authorizationError = null;
let invoice = null;

if (records.length === 0) {
  authorized = false;
  authorizationError =
    'invoice_not_found';
}

if (records.length > 1) {
  authorized = false;
  authorizationError =
    'processing_id_not_unique';
}

if (records.length === 1) {
  invoice = records[0];

  const assignedManagerId =
    String(invoice.manager_id ?? '').trim();

  const actorUserId =
    String(callback.actor_user_id ?? '').trim();

  const currentStatus =
    String(invoice.status ?? '')
      .trim()
      .toLowerCase();

  const currentDecision =
    String(invoice.approval_decision ?? '')
      .trim()
      .toLowerCase();

  if (!assignedManagerId) {
    authorized = false;
    authorizationError =
      'manager_not_assigned';
  } else if (
    assignedManagerId !== actorUserId
  ) {
    authorized = false;
    authorizationError =
      'manager_not_authorized';
  } } else {
  const action =
    String(callback.callback_action ?? '')
      .trim()
      .toLowerCase();

  const allowedStatusesByAction = {
    review: [
      'manual_review_pending'
    ],
    reject: [
      'manual_review_pending'
    ],
    approve: [
      'approval_pending'
    ],
    approval_reject: [
      'approval_pending'
    ]
  };

  const allowedStatuses =
    allowedStatusesByAction[action] ?? [];

  if (!allowedStatuses.includes(currentStatus)) {
    authorized = false;

    authorizationError =
      action === 'approve' ||
      action === 'approval_reject'
        ? 'invoice_not_pending_approval'
        : 'invoice_not_pending_review';
  } else if (
    currentDecision &&
    currentDecision !== 'pending'
  ) {
    authorized = false;
    authorizationError =
      'decision_already_recorded';
  }
}

return [
  {
    json: {
      ...callback,
      ...(invoice ?? {}),

      callback_action:
        callback.callback_action,

      actor_user_id:
        callback.actor_user_id,

      actor_username:
        callback.actor_username,

      actor_first_name:
        callback.actor_first_name,

      telegram_chat_id:
        callback.telegram_chat_id,

      telegram_message_id:
        callback.telegram_message_id,

      callback_query_id:
        callback.callback_query_id,

      authorized,
      authorization_error:
        authorizationError,

      authorized_at:
        authorized
          ? new Date().toISOString()
          : null
    }
  }
];

const invoice = $json;

const escapeHtml = (value) => {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
};

const reviewer =
  invoice.actor_username
    ? `@${invoice.actor_username}`
    : (
        invoice.actor_first_name ||
        `Telegram ID ${invoice.actor_user_id}`
      );

const existingComment =
  String(invoice.approval_comment ?? '')
    .trim();

const reviewComment =
  `Manual review completed by ${reviewer}`;

const approvalComment =
  existingComment
    ? `${existingComment}; ${reviewComment}`
    : reviewComment;

const resolutionMessage = [
  '🔍 <b>Manual review completed</b>',
  '',
  `<b>Supplier:</b> ${escapeHtml(invoice.vendor_name)}`,
  `<b>Invoice:</b> ${escapeHtml(invoice.invoice_number)}`,
  `<b>Amount:</b> ${escapeHtml(invoice.currency)} ${escapeHtml(invoice.total_amount)}`,
  '',
  `<b>Reviewed by:</b> ${escapeHtml(reviewer)}`,
  `<b>Review result:</b> Continue to final approval`,
  '',
  `<b>Detected risk:</b> ${escapeHtml(invoice.risk_flags)}`,
  '',
  'The invoice will now be sent for final approval.',
  '',
  `<a href="${escapeHtml(invoice.drive_file_url)}">Open invoice PDF</a>`
].join('\n');

return {
  json: {
    ...invoice,

    status: 'manual_review_completed',
    manual_review_decision: 'reviewed',

    approval_decision: 'pending',
    approval_comment: approvalComment,

    telegram_resolution_message:
      resolutionMessage,

    manual_review_completed_at:
      new Date().toISOString()
  }
};

