const resolutionMessage = [
  '❌ <b>Invoice rejected</b>',
  '',
  `<b>Supplier:</b> ${escapeHtml(invoice.vendor_name)}`,
  `<b>Invoice:</b> ${escapeHtml(invoice.invoice_number)}`,
  `<b>Amount:</b> ${escapeHtml(invoice.currency)} ${escapeHtml(invoice.total_amount)}`,
  '',
  `<b>Rejected by:</b> ${escapeHtml(reviewer)}`,
  `<b>Reason:</b> Manual review rejection`,
  '',
  `<b>Detected risk:</b> ${escapeHtml(invoice.risk_flags)}`,
  '',
  `<a href="${escapeHtml(invoice.drive_file_url)}">Open invoice PDF</a>`
].join('\n');

const now =
  new Date().toISOString();

return {
  json: {
    ...invoice,

    status: 'rejected',
    manual_review_decision: 'rejected',

    approval_decision: 'rejected',
    approval_comment: approvalComment,

    telegram_resolution_message:
      resolutionMessage,

    processed_at: now,
    rejected_at: now
  }
};

let decisionItem = null;

try {
  decisionItem =
    $('invoice__callback--prepare-reviewed').item;
} catch (error) {
  // Review branch wasn't executed.
}

if (!decisionItem) {
  try {
    decisionItem =
      $('invoice__callback--prepare-rejected').item;
  } catch (error) {
    // Reject branch wasn't executed.
  }
}

if (!decisionItem) {
  throw new Error(
    'MANUAL_REVIEW_DECISION_NOT_FOUND'
  );
}

return {
  json: {
    ...decisionItem.json,

    registry_updated: true,
    registry_row_number:
      $json.row_number ??
      $json.rowNumber ??
      null
  }
};

const decisionItem =
  $('invoice__callback--restore-decision').item;

if (!decisionItem) {
  throw new Error(
    'EDITED_DECISION_DATA_NOT_FOUND'
  );
}

return {
  json: {
    ...decisionItem.json,

    telegram_message_updated: true,
    callback_completed_at:
      new Date().toISOString()
  }
};

