        `Telegram ID ${invoice.actor_user_id}`
      );

const existingComment =
  String(invoice.approval_comment ?? '')
    .trim();

const decisionComment =
  `Final approval granted by ${approver}`;

const approvalComment =
  existingComment
    ? `${existingComment}; ${decisionComment}`
    : decisionComment;

const now =
  new Date().toISOString();

const resultMessage = [
  '✅ <b>Invoice approved</b>',
  '',
  `<b>Supplier:</b> ${escapeHtml(invoice.vendor_name)}`,
  `<b>Invoice:</b> ${escapeHtml(invoice.invoice_number)}`,
  `<b>Amount:</b> ${escapeHtml(invoice.currency)} ${escapeHtml(invoice.total_amount)}`,
  '',
  `<b>Approved by:</b> ${escapeHtml(approver)}`,
  `<b>Approved at:</b> ${escapeHtml(now)}`,
  '',
  'The invoice is ready for accounting export.',
  '',
  `<a href="${escapeHtml(invoice.drive_file_url)}">Open invoice PDF</a>`
].join('\n');

return {
  json: {
    ...invoice,

    status: 'approved',
    approval_decision: 'approved',
    approval_comment: approvalComment,

    final_decision_by:
      String(invoice.actor_user_id),

    final_decision_at: now,
    approved_at: now,
    processed_at: now,

    telegram_final_message:
      resultMessage
  }
};

