  '',
  `<b>Rejected by:</b> ${escapeHtml(approver)}`,
  `<b>Rejected at:</b> ${escapeHtml(now)}`,
  '',
  'The invoice will not be exported to accounting.',
  '',
  `<a href="${escapeHtml(invoice.drive_file_url)}">Open invoice PDF</a>`
].join('\n');

return {
  json: {
    ...invoice,

    status: 'rejected',
