    telegram_final_message:
      resultMessage
  }
};

let decisionItem = null;

try {
  decisionItem =
    $('invoice__callback--prepare-approved').item;
} catch (error) {
  // Approve branch wasn't executed.
}

if (!decisionItem) {
  try {
    decisionItem =
      $('invoice__callback--prepare-approval-rejected').item;
  } catch (error) {
    // Reject branch wasn't executed.
  }
}

if (!decisionItem) {
  throw new Error(
    'FINAL_APPROVAL_DECISION_NOT_FOUND'
  );
}

return {
  json: {
    ...decisionItem.json,

    registry_updated: true,
    registry_row_number:
      $json.row_number ??
      $json.rowNumber ??
      null
  }
};

const decisionItem =
  $('invoice__callback--restore-final-decision').item;

if (!decisionItem) {
  throw new Error(
    'FINAL_DECISION_DATA_NOT_FOUND'
  );
}

return {
  json: {
    ...decisionItem.json,

    telegram_message_updated: true,
    callback_completed_at:
      new Date().toISOString()
  }
};

const accountingResult = $json;

let approvedInvoice = {};

try {
  approvedInvoice =
    $('invoice__callback--return-final-decision').item.json;
} catch (error) {
  approvedInvoice = {};
}

const processingId =
  String(
    accountingResult.processing_id ||
    approvedInvoice.processing_id ||
    ''
  ).trim();

if (!processingId) {
  throw new Error(
    'ACCOUNTING_HANDOFF_PROCESSING_ID_MISSING'
  );
}

/*
 * Ця Code-нода запускається тільки після успішного завершення
 * invoice__subworkflow--export-accounting.
 *
 * Якщо accounting workflow завершиться помилкою,
 * n8n до цієї ноди не дійде.
 */
const accountingEntryId =
  accountingResult.accounting_entry_id ||
  approvedInvoice.accounting_entry_id ||
  `ACC-${approvedInvoice.invoice_id || processingId}`;

const accountingExportedAt =
  accountingResult.accounting_exported_at ||
  accountingResult.exported_at ||
  new Date().toISOString();

return {
  json: {
    ...approvedInvoice,
    ...accountingResult,

    processing_id:
      processingId,

    status:
      'accounting_exported',

    accounting_exported:
      true,

    accounting_entry_id:
      accountingEntryId,

    accounting_exported_at:
      accountingExportedAt,

    completion_handoff_created_at:
      new Date().toISOString(),
  },
};
